from flask import Flask, request, jsonify
from flask_jwt_extended import jwt_required, get_jwt_identity
from functools import wraps

app = Flask(__name__)

# Mock database
users = {
    1: {"id": 1, "username": "admin", "email": "admin@example.com", "role": "admin", "account_status": "active", "subscription_tier": "enterprise"},
    2: {"id": 2, "username": "user1", "email": "user1@example.com", "role": "user", "account_status": "active", "subscription_tier": "free"},
    3: {"id": 3, "username": "mod1", "email": "mod1@example.com", "role": "moderator", "account_status": "active", "subscription_tier": "pro"}
}

def admin_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        current_user_id = get_jwt_identity()
        current_user = users.get(current_user_id)
        if not current_user or current_user.get('role') != 'admin':
            return jsonify({"error": "Admin access required"}), 403
        return f(*args, **kwargs)
    return decorated_function

@app.route('/api/users/<int:user_id>', methods=['PUT'])
@jwt_required()
@admin_required
def update_user(user_id):
    current_user_id = get_jwt_identity()
    current_user = users.get(current_user_id)
    
    if not current_user:
        return jsonify({"error": "Current user not found"}), 404
    
    user = users.get(user_id)
    if not user:
        return jsonify({"error": "User not found"}), 404
    
    # Check if user belongs to same tenant (mocked)
    if user.get('id') != user_id:
        return jsonify({"error": "Unauthorized access"}), 403
    
    update_fields = {
        'email': request.json.get('email'),
        'username': request.json.get('username'),
        'role': request.json.get('role'),
        'account_status': request.json.get('account_status'),
        'subscription_tier': request.json.get('subscription_tier')
    }
    
    # Allowlist of updatable fields
    allowed_fields = {'email', 'username', 'role', 'account_status', 'subscription_tier'}
    updatable_fields = {k: v for k, v in update_fields.items() if k in allowed_fields and v is not None}
    
    # Role validation
    if 'role' in updatable_fields:
        if current_user.get('role') != 'admin':
            return jsonify({"error": "Only admin can change roles"}), 403
        if updatable_fields['role'] not in ['user', 'moderator', 'admin']:
            return jsonify({"error": "Invalid role"}), 400
    
    # Account status validation
    if 'account_status' in updatable_fields:
        if updatable_fields['account_status'] not in ['active', 'suspended']:
            return jsonify({"error": "Invalid account status"}), 400
    
    # Subscription tier validation
    if 'subscription_tier' in updatable_fields:
        if updatable_fields['subscription_tier'] not in ['free', 'pro', 'enterprise']:
            return jsonify({"error": "Invalid subscription tier"}), 400
    
    # Update user
    for field, value in updatable_fields.items():
        user[field] = value
    
    return jsonify(user), 200